import { Card, Stack, Row, Text, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city = 'Unknown',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const { motionEnabled } = useMotion();

  return (
    <>
      <MotionKeyframes />
      <section>
        <Card 
          padding="24" 
          shadow="md" 
          border={true}
          style={{
            animation: motionEnabled ? animation.fadeIn : 'none',
            maxWidth: '500px',
          }}
        >
          <Stack direction="vertical" gap={16}>
            {/* Header - City Name */}
            <div>
              <Text variant="h2" color="var(--ggui-color-onSurface, #18181b)">
                {city}
              </Text>
            </div>

            {/* Current Weather Section */}
            <Stack direction="vertical" gap={12} align="center">
              {/* Temperature Display */}
              <div style={{ textAlign: 'center' }}>
                <Text
                  variant="h1"
                  color="var(--ggui-color-primary-600, #0284c7)"
                  weight="bold"
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 36px)',
                    lineHeight: '1.2',
                  }}
                >
                  {temperature}°{unit}
                </Text>
              </div>

              {/* Condition with Icon */}
              <Stack direction="vertical" gap={8} align="center">
                <div style={{ fontSize: '64px', lineHeight: '1' }}>
                  {getWeatherIcon(condition)}
                </div>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="medium"
                >
                  {condition}
                </Text>
              </Stack>

              {/* Humidity and Wind Speed Row */}
              <Row gap={16} justify="center" align="center" wrap={false}>
                {/* Humidity */}
                <div style={{ textAlign: 'center' }}>
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    weight="medium"
                  >
                    Humidity
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                    weight="semibold"
                  >
                    {humidity}%
                  </Text>
                </div>

                {/* Wind Speed */}
                <div style={{ textAlign: 'center' }}>
                  <Text
                    variant="label"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    weight="medium"
                  >
                    Wind Speed
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                    weight="semibold"
                  >
                    {windSpeed} km/h
                  </Text>
                </div>
              </Row>
            </Stack>

            {/* Forecast Section */}
            {forecast && forecast.length > 0 && (
              <>
                <Divider orientation="horizontal" margin={16} />

                <div>
                  <Text
                    variant="h3"
                    color="var(--ggui-color-onSurface, #18181b)"
                    weight="semibold"
                    style={{ marginBottom: 'var(--ggui-spacing-2, 8px)', display: 'block' }}
                  >
                    5-Day Forecast
                  </Text>

                  <Stack direction="horizontal" gap={8} wrap={true} justify="between">
                    {forecast.map((item, index) => {
                      const dayLabel = item.day || 'Day ' + String(index + 1);
                      const highTemp = item.high !== undefined ? String(item.high) + '°' : '--';
                      const lowTemp = item.low !== undefined ? String(item.low) + '°' : '--';
                      return (
                        <div
                          key={index}
                          style={{
                            flex: '1 1 auto',
                            minWidth: '80px',
                            textAlign: 'center',
                            padding: 'var(--ggui-spacing-2, 8px)',
                            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                            backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                          }}
                        >
                          <Stack direction="vertical" gap={4} align="center">
                            {/* Day Name */}
                            <Text
                              variant="label"
                              color="var(--ggui-color-onSurfaceVariant, #52525b)"
                              weight="medium"
                            >
                              {dayLabel}
                            </Text>

                            {/* Weather Icon */}
                            <div style={{ fontSize: '32px', lineHeight: '1', margin: 'var(--ggui-spacing-1, 4px) 0' }}>
                              {item.icon || '☁️'}
                            </div>

                            {/* High Temperature */}
                            <Text
                              variant="body"
                              color="var(--ggui-color-onSurface, #18181b)"
                              weight="semibold"
                            >
                              {highTemp}
                            </Text>

                            {/* Low Temperature */}
                            <Text
                              variant="caption"
                              color="var(--ggui-color-onSurfaceVariant, #52525b)"
                            >
                              {lowTemp}
                            </Text>
                          </Stack>
                        </div>
                      );
                    })}
                  </Stack>
                </div>
              </>
            )}
          </Stack>
        </Card>
      </section>
    </>
  );
}

/**
 * Helper function to map weather conditions to emoji icons
 * Supports: Sunny, Cloudy, Rainy, Snowy, Stormy, Windy, etc.
 */
function getWeatherIcon(condition: string): string {
  const normalizedCondition = condition.toLowerCase().trim();

  const iconMap: Record<string, string> = {
    'sunny': '☀️',
    'clear': '☀️',
    'cloudless': '☀️',
    'cloudy': '☁️',
    'overcast': '☁️',
    'rainy': '🌧️',
    'rain': '🌧️',
    'drizzle': '🌦️',
    'snowy': '❄️',
    'snow': '❄️',
    'stormy': '⛈️',
    'thunderstorm': '⛈️',
    'windy': '💨',
    'foggy': '🌫️',
    'fog': '🌫️',
    'partly cloudy': '⛅',
    'partly sunny': '⛅',
    'hail': '🌨️',
    'sleet': '🌧️',
  };

  // Direct lookup or contains-based fallback
  if (iconMap[normalizedCondition]) {
    return iconMap[normalizedCondition];
  }

  for (const [key, icon] of Object.entries(iconMap)) {
    if (normalizedCondition.includes(key)) {
      return icon;
    }
  }

  // Default fallback
  return '🌤️';
}

import { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Input, Button, Box, Badge, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

function formatTime(timestamp?: string): string {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
}

export default function ChatWindow({ title = 'Chat', currentUser = 'You', participantCount = 2, messages = [], onSendMessage }: Props) {
  const [inputValue, setInputValue] = useState('');
  const messageListRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    if (messageListRef.current) {
      setTimeout(() => {
        messageListRef.current?.scrollTo({ top: messageListRef.current?.scrollHeight ?? 0, behavior: 'smooth' });
      }, 0);
    }
  }, [messages.length]);

  const handleSend = () => {
    if (inputValue.trim() && onSendMessage) {
      onSendMessage({ text: inputValue, timestamp: new Date().toISOString() });
      setInputValue('');
    }
  };

  const groupedMessages = messages.map((msg, index) => ({
    msg,
    index,
    isSameSenderAsPrevious: index > 0 && messages[index - 1].sender === msg.sender,
  }));

  const isOwnMessage = (sender?: string) => sender === currentUser;

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={16}
        shadow="md"
        border={true}
        style={{
          display: 'flex',
          flexDirection: 'column',
          height: '100%',
          maxHeight: '600px',
          backgroundColor: `var(--ggui-color-surfaceVariant, #f4f4f5)`,
        }}
      >
        <Stack direction="horizontal" gap={8} align="center" justify="between">
          <div style={{ display: 'flex', alignItems: 'center', gap: `var(--ggui-spacing-2, 8px)` }}>
            <Text variant="h3" weight="bold" color={`var(--ggui-color-onSurface, #18181b)`}>
              {title}
            </Text>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm" pill={true}>
                {participantCount} {participantCount === 1 ? 'participant' : 'participants'}
              </Badge>
            )}
          </div>
        </Stack>

        <Box
          ref={messageListRef}
          padding={16}
          style={{
            flex: 1,
            overflowY: 'auto',
            backgroundColor: `var(--ggui-color-surface, #fafafa)`,
            border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
            borderRadius: `var(--ggui-shape-radius-md, 8px)`,
            marginTop: `var(--ggui-spacing-4, 16px)`,
            marginBottom: `var(--ggui-spacing-4, 16px)`,
            display: 'flex',
            flexDirection: 'column',
            gap: `var(--ggui-spacing-2, 12px)`,
            scrollBehavior: 'smooth',
          }}
          role="log"
          aria-live="polite"
          aria-label="Chat messages"
        >
          {messages.length === 0 ? (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: `var(--ggui-color-onSurfaceVariant, #52525b)` }}>
              <Text variant="body">No messages yet. Start the conversation!</Text>
            </div>
          ) : (
            groupedMessages.map(({ msg, index, isSameSenderAsPrevious }) => {
              const isOwn = isOwnMessage(msg.sender);
              const slideDelay = motionEnabled ? (index % 5) * 30 : 0;
              const slideAnimation = motionEnabled ? animation.slideInUp : 'none';
              const delay = slideDelay + 'ms';

              return (
                <Stack
                  key={index}
                  direction="horizontal"
                  align="flex-end"
                  gap={8}
                  justify={isOwn ? 'end' : 'start'}
                  style={{ animation: slideAnimation, animationDelay: delay }}
                >
                  <Card padding={12} border={false} shadow="none" style={{ maxWidth: '70%', backgroundColor: isOwn ? `var(--ggui-color-primary-600, #0284c7)` : `var(--ggui-color-surfaceVariant, #f4f4f5)`, borderRadius: `var(--ggui-shape-radius-md, 8px)`, overflow: 'hidden', wordWrap: 'break-word' }}>
                    <Stack direction="vertical" gap={4}>
                      {!isSameSenderAsPrevious && (
                        <Text variant="caption" weight="medium" color={isOwn ? `var(--ggui-color-primary-50, rgba(240, 249, 255, 0.9))` : `var(--ggui-color-onSurfaceVariant, #52525b)`}>
                          {msg.sender || 'Unknown'}
                        </Text>
                      )}
                      <Text variant="body" color={isOwn ? `var(--ggui-color-primary-50, #ffffff)` : `var(--ggui-color-onSurface, #18181b)`} style={{ wordWrap: 'break-word', whiteSpace: 'pre-wrap' }}>
                        {msg.text || ''}
                      </Text>
                      <Text variant="caption" color={isOwn ? `var(--ggui-color-primary-100, rgba(224, 242, 254, 0.7))` : `var(--ggui-color-onSurfaceVariant, #52525b)`}>
                        {formatTime(msg.timestamp)}
                      </Text>
                    </Stack>
                  </Card>
                </Stack>
              );
            })
          )}
        </Box>

        <Stack direction="horizontal" gap={8} align="end">
          <Input label="Message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} style={{ flex: 1 }} />
          <Button variant="primary" size="sm" disabled={!inputValue.trim()} onClick={handleSend}>
            Send
          </Button>
        </Stack>
      </Card>
    </>
  );
}

