import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Box,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const { motionEnabled } = useMotion();
  const [connectionStatus, setConnectionStatus] = useState<'idle' | 'connecting' | 'connected'>('idle');
  const [displayedStocks, setDisplayedStocks] = useState<Stock[]>(stocks || []);
  const [lastUpdateTime, setLastUpdateTime] = useState<string | undefined>(lastUpdated);

  // Listen for agent data stream
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      try {
        const customEvent = event as CustomEvent;
        const { stocks: newStocks, timestamp } = customEvent.detail || {};

        // Validate and filter stock data
        if (Array.isArray(newStocks)) {
          const validStocks = newStocks.filter(
            (s: Stock) => s && s.symbol && typeof s.price === 'number'
          );
          setDisplayedStocks(validStocks);
          setConnectionStatus('connected');

          if (timestamp) {
            setLastUpdateTime(timestamp);
          }
        }
      } catch (error) {
        console.error('Error processing agent data:', error);
      }
    };

    // Use globalThis for better compatibility
    if (typeof globalThis !== 'undefined') {
      globalThis.addEventListener('ggui:agent-data', handleAgentData);

      return () => {
        globalThis.removeEventListener('ggui:agent-data', handleAgentData);
      };
    }
  }, []);

  // Format timestamp for display
  const formatTimestamp = (iso?: string): string => {
    if (!iso) return 'N/A';
    try {
      const date = new Date(iso);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: true,
      });
    } catch {
      return 'N/A';
    }
  };

  return (
    <Container maxWidth="lg" padding={24}>
      <MotionKeyframes />

      <Stack direction="vertical" gap={24}>
        {/* Header Section */}
        <Box
          background="var(--ggui-color-container, #ede9fe)"
          padding={16}
          borderRadius="var(--ggui-shape-radius-md, 8px)"
          style={{
            borderBottom: '2px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack
            direction="horizontal"
            justify="between"
            align="center"
            gap={16}
          >
            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-onContainer, #4c1d95)"
            >
              Market Watch
            </Text>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Last Updated: {formatTimestamp(lastUpdateTime)}
            </Text>
          </Stack>
        </Box>

        {/* Connecting State */}
        {connectionStatus === 'connecting' && (
          <Box
            background="var(--ggui-color-primary-50, #f0f9ff)"
            padding={12}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              animation: motionEnabled ? 'pulse 2s infinite' : 'none',
            }}
          >
            <Text
              variant="body"
              color="var(--ggui-color-primary-700, #0369a1)"
              role="status"
              aria-live="polite"
            >
              ✓ Connecting to market data...
            </Text>
          </Box>
        )}

        {/* Empty State */}
        {displayedStocks.length === 0 && connectionStatus === 'idle' && (
          <Box
            padding={48}
            style={{
              textAlign: 'center',
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            }}
            role="status"
            aria-live="polite"
          >
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              No stocks loaded yet
            </Text>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              style={{ display: 'block', marginTop: '8px' }}
            >
              Waiting for live market data...
            </Text>
          </Box>
        )}

        {/* Stock Grid */}
        <Stack
          direction="horizontal"
          wrap={true}
          gap={16}
          role="region"
          aria-label="Stock market data"
          style={{
            display: 'flex',
            flexFlow: 'row wrap',
          }}
        >
          {displayedStocks.map((stock, index) => {
            const isPositive = (stock.changePercent ?? 0) >= 0;
            const arrowIcon = isPositive ? '▲' : '▼';
            const changeColor = isPositive
              ? 'var(--ggui-color-success-500, #22c55e)'
              : 'var(--ggui-color-error-500, #ef4444)';
            const safeSymbol = String(stock.symbol || 'N/A');
            const safeName = String(stock.name || 'Unknown');
            const animationDelay = (index * 50) + 'ms';

            return (
              <div
                key={'stock' + index}
                style={{
                  flex: '1 1 calc(33.333% - 12px)',
                  minWidth: '250px',
                  animation: motionEnabled
                    ? animation.slideInUp
                    : 'none',
                  animationDelay: motionEnabled ? animationDelay : '0ms',
                  transition: 'all 0.3s ease-out',
                }}
              >
                <Card
                  padding={16}
                  shadow="sm"
                  border={true}
                  style={{
                    borderLeft: '3px solid ' + changeColor,
                    height: '100%',
                    backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                  role="article"
                  aria-label={'Stock: ' + safeSymbol + ' - ' + safeName}
                >
                  <Stack direction="vertical" gap={12}>
                    {/* Symbol */}
                    <Text
                      variant="h3"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {safeSymbol}
                    </Text>

                    {/* Company Name */}
                    {stock.name && (
                      <Text
                        variant="body"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {safeName}
                      </Text>
                    )}

                    {/* Price */}
                    <Text
                      variant="h2"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      style={{
                        fontSize: 'var(--ggui-font-size-2xl, 24px)',
                      }}
                    >
                      {'$' + (stock.price ?? 0).toFixed(2)}
                    </Text>

                    {/* Change Row */}
                    <Stack
                      direction="horizontal"
                      gap={8}
                      align="center"
                      style={{
                        marginTop: '4px',
                      }}
                    >
                      <Text
                        variant="body"
                        weight="medium"
                        color={changeColor}
                        style={{
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                        }}
                      >
                        {arrowIcon + ' ' + (stock.change ?? 0).toFixed(2)}
                      </Text>
                      <Text
                        variant="label"
                        weight="medium"
                        color={changeColor}
                        style={{
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                        }}
                      >
                        {'(' + (stock.changePercent ?? 0).toFixed(2) + '%)'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              </div>
            );
          })}
        </Stack>
      </Stack>

      {/* Pulse animation keyframe */}
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }

        @media (max-width: 1023px) {
          div[style*="flex: 1 1 calc(33.333%"] {
            flex-basis: calc(50% - 8px) !important;
          }
        }

        @media (max-width: 639px) {
          div[style*="flex: 1 1 calc(33.333%"] {
            flex-basis: 100% !important;
          }
        }
      `}</style>
    </Container>
  );
}

import { Container, Card, Stack, Row, Box, Text, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const lower = condition.toLowerCase();
  if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
  if (lower.includes('partly cloudy') || lower.includes('partly')) return '⛅';
  if (lower.includes('cloud') || lower.includes('overcast')) return '☁️';
  if (lower.includes('rain') || lower.includes('drizzle') || lower.includes('shower')) return '🌧️';
  if (lower.includes('thunder') || lower.includes('storm')) return '⛈️';
  if (lower.includes('snow') || lower.includes('blizzard')) return '❄️';
  if (lower.includes('fog') || lower.includes('mist') || lower.includes('haze')) return '🌫️';
  if (lower.includes('wind')) return '💨';
  return '🌤️';
}

