import { useState } from 'react';
import {
  Container, Card, Box, Stack, Row, Text, Input, TextArea,
  Button, Checkbox, RadioGroup, Divider, Spacer, Icon, Badge,
  Toast, MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers as a structured object */
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: string;
    satisfactionLabel: string;
    selectedFeatures: string[];
    comments: string;
  }) => void | Promise<void>;
}

const TOTAL_STEPS = 4;
const MAX_COMMENTS = 500;
const COMMENTS_WARN_THRESHOLD = 450;

export default function GeneratedComponent({
  featureOptions = ['Dashboard', 'Reporting', 'Integrations', 'API Access', 'Mobile App'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState(0);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [animKey, setAnimKey] = useState(0);

  const validateName = (value: string): string => {
    if (!value.trim()) return 'Name is required';
    return '';
  };

  const validateEmail = (value: string): string => {
    if (!value.trim()) return 'Email is required';
    if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(value)) return 'Please enter a valid email address';
    return '';
  };

  const handleNameChange = (value: string) => {
    setName(value);
    if (touched.name) {
      setErrors(prev => ({ ...prev, name: validateName(value) }));
    }
  };

  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (touched.email) {
      setErrors(prev => ({ ...prev, email: validateEmail(value) }));
    }
  };

  const toggleFeature = (feature: string, checked: boolean) => {
    setSelectedFeatures(prev =>
      checked ? [...prev, feature] : prev.filter(f => f !== feature)
    );
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= MAX_COMMENTS) setComments(value);
  };

  const isStepValid = (s: number): boolean => {
    switch (s) {
      case 0: return name.trim() !== '' && email.trim() !== '' && !validateName(name) && !validateEmail(email);
      case 1: return satisfaction !== '';
      case 2: return true;
      case 3: return true;
      default: return true;
    }
  };

  const goNext = () => {
    if (step === 0) {
      const nameErr = validateName(name);
      const emailErr = validateEmail(email);
      setTouched({ name: true, email: true });
      setErrors(prev => ({ ...prev, name: nameErr, email: emailErr }));
      if (nameErr || emailErr) return;
    }
    setStep(s => Math.min(s + 1, TOTAL_STEPS));
    setAnimKey(k => k + 1);
  };

  const goBack = () => {
    setStep(s => Math.max(s - 1, 0));
    setAnimKey(k => k + 1);
  };

  const handleSubmit = async () => {
    if (!onSubmit) return;
    setIsSubmitting(true);
    setSubmitStatus('idle');
    try {
      const satisfactionIndex = parseInt(satisfaction, 10) - 1;
      await onSubmit({
        name: name.trim(),
        email: email.trim(),
        satisfaction,
        satisfactionLabel: satisfactionLabels[satisfactionIndex] || satisfaction,
        selectedFeatures,
        comments: comments.trim(),
      });
      setSubmitStatus('success');
    } catch {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const progressPercent = step === TOTAL_STEPS ? 100 : ((step + 1) / TOTAL_STEPS) * 100;
  const currentStepNum = step + 1;
  const stepLabel = step < TOTAL_STEPS ? ('Step ' + currentStepNum + ' of ' + TOTAL_STEPS) : 'Review & Submit';
  const progressLabel = 'Survey progress: ' + stepLabel;
  const progressRounded = Math.round(progressPercent);
  const progressComplete = progressRounded + '% complete';
  const stepTitles = ['Your Information', 'Satisfaction Rating', 'Feature Interests', 'Additional Comments', 'Review Your Answers'];
  const satisfactionOptions = satisfactionLabels.map((label, i) => ({
    value: String(i + 1),
    label: (i + 1) + ' — ' + label,
  }));

  const charCount = comments.length + ' / ' + MAX_COMMENTS + ' characters';
  const charCountColor = comments.length >= COMMENTS_WARN_THRESHOLD
    ? 'var(--ggui-color-error-500, #ef4444)'
    : 'var(--ggui-color-onSurfaceVariant, #52525b)';

  const satisfactionReviewText = satisfaction
    ? satisfaction + ' — ' + (satisfactionLabels[parseInt(satisfaction, 10) - 1] || '')
    : 'Not provided';

  const reviewBoxStyle = {
    padding: 16,
    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md">
        <Card padding={32} shadow="md">
          <div role="form" aria-label="Survey Form">
            <Stack direction="vertical" gap={24}>

              <Text variant="h2" align="center" color="var(--ggui-color-onSurface, #18181b)">Survey</Text>

              <Stack direction="vertical" gap={8}>
                <Row justify="between" align="center">
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">{stepLabel}</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{progressComplete}</Text>
                </Row>
                <div
                  role="progressbar"
                  aria-valuenow={progressRounded}
                  aria-valuemin={0}
                  aria-valuemax={100}
                  aria-label={progressLabel}
                  style={{
                    width: '100%',
                    height: 8,
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    background: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                    overflow: 'hidden',
                  }}
                >
                  <div style={{
                    width: progressPercent + '%',
                    height: '100%',
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    background: 'var(--ggui-color-primary-500, #0ea5e9)',
                    transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)',
                  }} />
                </div>
                <Row gap={4} justify="center">
                  {Array.from({ length: TOTAL_STEPS }, (_, i) => (
                    <div
                      key={i}
                      aria-hidden="true"
                      style={{
                        width: i === step ? 24 : 8,
                        height: 8,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: i < step
                          ? 'var(--ggui-color-primary-500, #0ea5e9)'
                          : i === step
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                        transition: 'all 300ms cubic-bezier(0.4, 0, 0.2, 1)',
                      }}
                    />
                  ))}
                </Row>
              </Stack>

              <Divider margin={0} />

              <div
                key={animKey}
                aria-live="polite"
                style={{ animation: motionEnabled ? animation.fadeIn : 'none', minHeight: 200 }}
              >

                {step === 0 && (
                  <Stack direction="vertical" gap={16}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">{stepTitles[0]}</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please provide your name and email address.</Text>
                    <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} required error={touched.name ? errors.name : undefined} />
                    <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={handleEmailChange} required error={touched.email ? errors.email : undefined} />
                  </Stack>
                )}

                {step === 1 && (
                  <Stack direction="vertical" gap={16}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">{stepTitles[1]}</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">How satisfied are you with our service?</Text>
                    <RadioGroup label="Satisfaction Level" value={satisfaction} onChange={setSatisfaction} options={satisfactionOptions} direction="vertical" />
                  </Stack>
                )}

                {step === 2 && (
                  <Stack direction="vertical" gap={16}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">{stepTitles[2]}</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select any features you are interested in. (Optional)</Text>
                    <Stack direction="vertical" gap={8}>
                      {featureOptions.map(feature => (
                        <Checkbox
                          key={feature}
                          label={feature}
                          checked={selectedFeatures.includes(feature)}
                          onChange={(checked) => toggleFeature(feature, checked)}
                        />
                      ))}
                    </Stack>
                  </Stack>
                )}

                {step === 3 && (
                  <Stack direction="vertical" gap={16}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">{stepTitles[3]}</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Share any additional thoughts or feedback. (Optional)</Text>
                    <TextArea label="Comments" placeholder="Type your comments here..." value={comments} onChange={handleCommentsChange} rows={5} maxLength={MAX_COMMENTS} />
                    <Text variant="caption" align="right" color={charCountColor}>{charCount}</Text>
                  </Stack>
                )}

                {step === 4 && (
                  <Stack direction="vertical" gap={16}>
                    <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">{stepTitles[4]}</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please review your answers before submitting.</Text>

                    <Box padding={reviewBoxStyle.padding} background={reviewBoxStyle.background} borderRadius={reviewBoxStyle.borderRadius}>
                      <Stack direction="vertical" gap={8}>
                        <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">Personal Information</Text>
                        <Row gap={8}>
                          <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name:</Text>
                          <Text color="var(--ggui-color-onSurface, #18181b)">{name}</Text>
                        </Row>
                        <Row gap={8}>
                          <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email:</Text>
                          <Text color="var(--ggui-color-onSurface, #18181b)">{email}</Text>
                        </Row>
                      </Stack>
                    </Box>

                    <Box padding={reviewBoxStyle.padding} background={reviewBoxStyle.background} borderRadius={reviewBoxStyle.borderRadius}>
                      <Stack direction="vertical" gap={8}>
                        <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">Satisfaction Rating</Text>
                        <Row gap={8}>
                          <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">Rating:</Text>
                          <Text color="var(--ggui-color-onSurface, #18181b)">{satisfactionReviewText}</Text>
                        </Row>
                      </Stack>
                    </Box>

                    <Box padding={reviewBoxStyle.padding} background={reviewBoxStyle.background} borderRadius={reviewBoxStyle.borderRadius}>
                      <Stack direction="vertical" gap={8}>
                        <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">Feature Interests</Text>
                        <Row gap={8} wrap>
                          {selectedFeatures.length > 0 ? (
                            selectedFeatures.map(feature => (
                              <Badge key={feature} variant="primary" size="sm">{feature}</Badge>
                            ))
                          ) : (
                            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
                          )}
                        </Row>
                      </Stack>
                    </Box>

                    <Box padding={reviewBoxStyle.padding} background={reviewBoxStyle.background} borderRadius={reviewBoxStyle.borderRadius}>
                      <Stack direction="vertical" gap={8}>
                        <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">Additional Comments</Text>
                        <Text color="var(--ggui-color-onSurface, #18181b)">{comments.trim() || 'No comments provided'}</Text>
                      </Stack>
                    </Box>
                  </Stack>
                )}

              </div>

              <Divider margin={0} />

              <Row justify="between" align="center">
                {step > 0 ? (
                  <Button
                    variant="outline"
                    onClick={goBack}
                    disabled={isSubmitting}
                    leftIcon={<Icon name="chevron-left" size={16} />}
                  >
                    Back
                  </Button>
                ) : (
                  <Spacer size={1} />
                )}
                {step < TOTAL_STEPS ? (
                  <Button
                    variant="primary"
                    onClick={goNext}
                    disabled={!isStepValid(step)}
                    rightIcon={<Icon name="chevron-right" size={16} />}
                  >
                    Next
                  </Button>
                ) : (
                  <Button
                    variant="primary"
                    onClick={handleSubmit}
                    disabled={isSubmitting}
                    loading={isSubmitting}
                    leftIcon={!isSubmitting ? <Icon name="check" size={16} /> : undefined}
                  >
                    {isSubmitting ? 'Submitting...' : 'Submit Survey'}
                  </Button>
                )}
              </Row>

            </Stack>
          </div>
        </Card>

        <Toast
          message="Your survey has been submitted successfully. Thank you for your feedback!"
          variant="success"
          title="Survey Submitted"
          visible={submitStatus === 'success'}
          onClose={() => setSubmitStatus('idle')}
          duration={5000}
        />
        <Toast
          message="There was an error submitting your survey. Please try again."
          variant="error"
          title="Submission Failed"
          visible={submitStatus === 'error'}
          onClose={() => setSubmitStatus('idle')}
          duration={5000}
        />
      </Container>
    </>
  );
}

import { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Divider,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    electronConfiguration?: string;
    row?: number;
    col?: number;
  }>;
}

