type ElementData = Props['elements'][number];

function buildCellAriaLabel(el: ElementData): string {
  const name = el.name ?? el.symbol ?? 'Unknown';
  const num = el.atomicNumber != null ? String(el.atomicNumber) : 'unknown';
  return 'Element: ' + name + ', Atomic number ' + num;
}

export default function GeneratedComponent({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const { motionEnabled } = useMotion();

  const matchingSet = useMemo(() => {
    if (!searchQuery.trim()) return null;
    const q = searchQuery.trim().toLowerCase();
    const matching = new Set<number>();
    elements.forEach((el) => {
      if (el.name?.toLowerCase().includes(q) || el.symbol?.toLowerCase().includes(q)) {
        matching.add(el.atomicNumber ?? -1);
      }
    });
    return matching;
  }, [searchQuery, elements]);

  const presentCategories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => { if (el.category) cats.add(el.category); });
    return Array.from(cats).sort();
  }, [elements]);

  const handleElementClick = (el: ElementData) => {
    setSelectedElement((prev) => prev?.atomicNumber === el.atomicNumber ? null : el);
  };

  const handleElementKeyDown = (e: React.KeyboardEvent, el: ElementData) => {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); handleElementClick(el); }
  };

  const handleCellFocus = (e: React.FocusEvent<HTMLDivElement>) => {
    e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
    e.currentTarget.style.outlineOffset = '2px';
  };

  const handleCellBlur = (e: React.FocusEvent<HTMLDivElement>) => {
    e.currentTarget.style.outline = 'none';
    e.currentTarget.style.outlineOffset = '0px';
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding={24}>
        <Stack direction="vertical" gap={24}>

          <Text variant="h1" align="center" color="var(--ggui-color-onSurface, #18181b)">
            Periodic Table of Elements
          </Text>

          <Stack direction="vertical" gap={4} align="center">
            <Text as="label" htmlFor="element-search" variant="label" color="var(--ggui-color-onSurface, #18181b)">Search Elements</Text>
            <Input label="Search Elements" placeholder="Search by name or symbol..." value={searchQuery} onChange={setSearchQuery} />
          </Stack>

          <div
            role="grid"
            aria-label="Periodic Table of Elements"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))',
              gridAutoRows: 'minmax(58px, auto)',
              gap: 'var(--ggui-spacing-1, 4px)',
              overflowX: 'auto',
              padding: 'var(--ggui-spacing-2, 8px) 0',
            }}
          >
            {elements.map((el) => {
              const isMatch = matchingSet === null || matchingSet.has(el.atomicNumber ?? -1);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const bgColor = CATEGORY_COLORS[el.category ?? ''] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)';
              const textColor = CATEGORY_TEXT_COLORS[el.category ?? ''] ?? 'var(--ggui-color-onSurface, #18181b)';

              return (
                <div
                  key={el.atomicNumber ?? el.symbol}
                  role="button"
                  tabIndex={0}
                  aria-label={buildCellAriaLabel(el)}
                  onClick={() => handleElementClick(el)}
                  onKeyDown={(e) => handleElementKeyDown(e, el)}
                  onFocus={handleCellFocus}
                  onBlur={handleCellBlur}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    backgroundColor: bgColor,
                    color: textColor,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    border: isSelected
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    cursor: 'pointer',
                    opacity: isMatch ? 1 : 0.15,
                    transition: 'opacity 200ms ease, box-shadow 200ms ease, border-color 200ms ease, transform 100ms ease',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                    transform: isSelected ? 'scale(1.08)' : 'scale(1)',
                    zIndex: isSelected ? 2 : 1,
                    minWidth: 0,
                    overflow: 'hidden',
                    outline: 'none',
                  }}
                >
                  <span style={{
                    position: 'absolute',
                    top: 'var(--ggui-spacing-1, 4px)',
                    left: 'var(--ggui-spacing-1, 4px)',
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    fontWeight: 'var(--ggui-font-weight-normal, 400)',
                    lineHeight: 1,
                  }}>
                    {el.atomicNumber}
                  </span>
                  <span style={{
                    fontSize: 'var(--ggui-font-size-lg, 18px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    lineHeight: 1.2,
                    marginTop: 6,
                  }}>
                    {el.symbol}
                  </span>
                </div>
              );
            })}
          </div>

          <div>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Legend</Text>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--ggui-spacing-4, 16px)', marginTop: 'var(--ggui-spacing-2, 8px)' }}>
              {presentCategories.map((cat) => (
                <div key={cat} style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                  <div
                    aria-hidden="true"
                    style={{
                      width: 16,
                      height: 16,
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      backgroundColor: CATEGORY_COLORS[cat] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      flexShrink: 0,
                    }}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                    {CATEGORY_LABELS[cat] ?? cat}
                  </Text>
                </div>
              ))}
            </div>
          </div>

          <Divider margin={0} />

          {selectedElement && (
            <div style={{ animation: motionEnabled ? animation.slideInUp : 'none' }}>
              <Card padding={24} shadow="md" border>
                <div aria-live="polite">
                  <Stack direction="vertical" gap={16}>

                    <Row gap={16} align="center">
                      <div style={{
                        width: 64,
                        height: 64,
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        backgroundColor: CATEGORY_COLORS[selectedElement.category ?? ''] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        color: CATEGORY_TEXT_COLORS[selectedElement.category ?? ''] ?? 'var(--ggui-color-onSurface, #18181b)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: 'var(--ggui-font-size-2xl, 24px)',
                        fontWeight: 'var(--ggui-font-weight-bold, 700)',
                        flexShrink: 0,
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}>
                        {selectedElement.symbol}
                      </div>
                      <Stack direction="vertical" gap={2}>
                        <Text variant="h2" color="var(--ggui-color-onSurface, #18181b)">
                          {selectedElement.name ?? 'Unknown'}
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {CATEGORY_LABELS[selectedElement.category ?? ''] ?? selectedElement.category ?? 'Unknown category'}
                        </Text>
                      </Stack>
                    </Row>

                    <Divider margin={8} />

                    <div style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                      gap: 'var(--ggui-spacing-4, 16px)',
                    }}>
                      <Stack direction="vertical" gap={2}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                        <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                          {selectedElement.atomicNumber ?? '—'}
                        </Text>
                      </Stack>

                      <Stack direction="vertical" gap={2}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Symbol</Text>
                        <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                          {selectedElement.symbol ?? '—'}
                        </Text>
                      </Stack>

                      <Stack direction="vertical" gap={2}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                        <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                          {selectedElement.atomicWeight != null ? selectedElement.atomicWeight : '—'}
                        </Text>
                      </Stack>

                      <Stack direction="vertical" gap={2}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Electron Configuration</Text>
