                  </Stack>
                </div>
              </Card>
            </div>
          )}

        </Stack>
      </Container>
    </>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import {
  Card, Row, Box, Text, Badge, Input, Button, Icon,
  MotionKeyframes, useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface MessageItem {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Called when user sends a message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

interface MessageGroup {
  sender: string;
  messages: Array<{ text: string; timestamp: string }>;
}

const LG = 'var(--ggui-shape-radius-lg, 12px)';
const SM = 'var(--ggui-shape-radius-sm, 4px)';

const OWN_RADII = [
  LG,
  LG + ' ' + LG + ' ' + SM + ' ' + LG,
  LG + ' ' + SM + ' ' + SM + ' ' + LG,
  LG + ' ' + SM + ' ' + LG + ' ' + LG,
];

const OTHER_RADII = [
  LG,
  LG + ' ' + LG + ' ' + LG + ' ' + SM,
  SM + ' ' + LG + ' ' + LG + ' ' + SM,
  SM + ' ' + LG + ' ' + LG + ' ' + LG,
];

function ownRadius(idx: number, total: number): string {
  if (total === 1) return OWN_RADII[0];
  if (idx === 0) return OWN_RADII[1];
  if (idx === total - 1) return OWN_RADII[3];
  return OWN_RADII[2];
}

function otherRadius(idx: number, total: number): string {
  if (total === 1) return OTHER_RADII[0];
  if (idx === 0) return OTHER_RADII[1];
  if (idx === total - 1) return OTHER_RADII[3];
  return OTHER_RADII[2];
}

function formatTimestamp(iso?: string): string {
  if (!iso) return '';
  try {
    const date = new Date(iso);
    return date.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' });
  } catch {
    return '';
  }
}

function groupMessages(messages: MessageItem[]): MessageGroup[] {
  const groups: MessageGroup[] = [];
  for (const msg of messages) {
    const sender = msg.sender ?? 'Unknown';
    const text = msg.text ?? '';
    const timestamp = msg.timestamp ?? '';
    if (groups.length > 0 && groups[groups.length - 1].sender === sender) {
      groups[groups.length - 1].messages.push({ text, timestamp });
    } else {
      groups.push({ sender, messages: [{ text, timestamp }] });
    }
  }
  return groups;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount,
  messages = [],
  onSendMessage,
}: Props) {
  const [inputValue, setInputValue] = useState('');
  const [streamedMessages, setStreamedMessages] = useState<MessageItem[]>([]);
  const messageListRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  const allMessages = [...messages, ...streamedMessages];
  const groups = groupMessages(allMessages);

  // Auto-scroll to bottom whenever messages change
  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, [allMessages.length]);

  // Stream Contract: listen on container element for incoming agent messages
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const handler = (e: Event) => {
      const detail = (e as CustomEvent).detail;
      if (detail && typeof detail === 'object') {
        setStreamedMessages(prev => [...prev, detail as MessageItem]);
      }
    };
    el.addEventListener('ggui:agent-data', handler);
    return () => el.removeEventListener('ggui:agent-data', handler);
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    if (onSendMessage) {
      onSendMessage(payload);
    }
    setStreamedMessages(prev => [...prev, { sender: currentUser, ...payload }]);
    setInputValue('');
  }, [inputValue, currentUser, onSendMessage]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  const canSend = inputValue.trim().length > 0;

  return (
    <>
      <MotionKeyframes />
      <div ref={containerRef}>
        <Card padding={0} shadow="md" border>
          <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: 480, maxHeight: '80vh' }}>

            {/* HEADER */}
            <div style={{ padding: 'var(--ggui-spacing-4, 16px)', backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)', borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)', flexShrink: 0 }}>
              <Row justify="between" align="center">
                <Text variant="h3" color="var(--ggui-color-primary-900, #0c4a6e)">{title}</Text>
                {participantCount != null && (
                  <div aria-label={participantCount + ' participants'}>
                    <Badge variant="primary" size="sm" pill>
                      <span style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}>
                        <Icon name="user" size={12} />
                        {participantCount}
                      </span>
                    </Badge>
                  </div>
                )}
              </Row>
            </div>

            {/* MESSAGE LIST */}
            <div ref={messageListRef} role="log" aria-live="polite" aria-label="Chat messages" style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', backgroundColor: 'var(--ggui-color-surface, #fafafa)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)' }}>
              {groups.length === 0 && (
                <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 'var(--ggui-spacing-8, 32px) 0' }}>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">No messages yet. Start the conversation!</Text>
                </div>
              )}
              {groups.map((group, groupIndex) => {
                const isOwn = group.sender === currentUser;
                const total = group.messages.length;
                return (
                  <div key={'group-' + groupIndex} style={{ display: 'flex', flexDirection: 'column', alignItems: isOwn ? 'flex-end' : 'flex-start', gap: 'var(--ggui-spacing-1, 4px)' }}>
                    {!isOwn && (
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{group.sender}</Text>
                    )}
                    {group.messages.map((msg, msgIndex) => {
                      const isLast = msgIndex === total - 1;
                      const radius = isOwn ? ownRadius(msgIndex, total) : otherRadius(msgIndex, total);
                      return (
                        <div key={'msg-' + groupIndex + '-' + msgIndex} style={{ maxWidth: '75%', animation: motionEnabled ? animation.fadeIn : 'none' }}>
                          <Box
                            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                            background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                            borderRadius={radius}
                          >
                            <Text variant="body" color={isOwn ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurface, #18181b)'}>{msg.text}</Text>
                          </Box>
                          {isLast && msg.timestamp && (
                            <div style={{ marginTop: 'var(--ggui-spacing-1, 4px)', textAlign: isOwn ? 'right' : 'left' }}>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align={isOwn ? 'right' : 'left'}>{formatTimestamp(msg.timestamp)}</Text>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                );
              })}
            </div>

            {/* INPUT AREA */}
            <div style={{ padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)', backgroundColor: 'var(--ggui-color-surface, #fafafa)', flexShrink: 0 }} onKeyDown={handleKeyDown}>
              <Row gap={8} align="center">
                <div style={{ flex: 1 }}>
                  <Input label="Message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} />
                </div>
                <Button variant="primary" onClick={handleSend} disabled={!canSend} aria-label="Send message" rightIcon={<Icon name="chevron-right" size={16} />}>Send</Button>
              </Row>
            </div>

          </div>
        </Card>
      </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import {
  Container, Card, Box, Stack, Row, Text, Badge,
  MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface StockItem {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: StockItem[];
  lastUpdated?: string;
}

const DEFAULT_STOCKS: StockItem[] = [
  { symbol: 'AAPL', name: 'Apple Inc.', price: 178.72, change: 2.35, changePercent: 1.33 },
  { symbol: 'GOOGL', name: 'Alphabet Inc.', price: 141.80, change: -0.95, changePercent: -0.67 },
  { symbol: 'MSFT', name: 'Microsoft Corp.', price: 378.91, change: 4.12, changePercent: 1.10 },
  { symbol: 'AMZN', name: 'Amazon.com Inc.', price: 185.07, change: -1.23, changePercent: -0.66 },
  { symbol: 'TSLA', name: 'Tesla Inc.', price: 248.42, change: 7.89, changePercent: 3.28 },
  { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 875.28, change: 12.56, changePercent: 1.46 },
];

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const initialStocks = props.stocks ?? DEFAULT_STOCKS;
  const initialLastUpdated = props.lastUpdated ?? new Date().toISOString();

  const [stocks, setStocks] = useState<StockItem[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string>(initialLastUpdated);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'disconnected'>('connecting');

  useEffect(() => {
    if (props.stocks) setStocks(props.stocks);
  }, [props.stocks]);

  useEffect(() => {
    if (props.lastUpdated) setLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  // Stream Contract: ggui:agent-data
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const detail = (event as CustomEvent).detail;
      if (!detail) return;
      if (Array.isArray(detail.stocks)) setStocks(detail.stocks);
      if (detail.lastUpdated) setLastUpdated(detail.lastUpdated);
      setConnectionStatus('connected');
    };

    const connectTimeout = setTimeout(() => {
      setConnectionStatus((prev) => (prev === 'connecting' ? 'connected' : prev));
    }, 2000);

    const target = typeof globalThis !== 'undefined' ? (globalThis as unknown as EventTarget) : null;
    if (target) target.addEventListener('ggui:agent-data', handleAgentData);

    return () => {
      if (target) target.removeEventListener('ggui:agent-data', handleAgentData);
      clearTimeout(connectTimeout);
    };
  }, []);

  const formatPrice = (price?: number): string => {
    if (price == null) return '\u2014';
    return '$' + price.toFixed(2);
  };

  const formatChange = (change?: number): string => {
    if (change == null) return '\u2014';
    const sign = change >= 0 ? '+' : '';
    return sign + change.toFixed(2);
  };

  const formatChangePercent = (pct?: number): string => {
    if (pct == null) return '\u2014';
    const sign = pct >= 0 ? '+' : '';
    return sign + pct.toFixed(2) + '%';
  };

  const isPositive = (change?: number): boolean => (change ?? 0) >= 0;

  const getChangeColor = (change?: number): string =>
    isPositive(change)
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';

  const getCardBorderColor = (change?: number): string =>
    isPositive(change)
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';

  const formatTimestamp = (iso?: string): string => {
    if (!iso) return 'N/A';
    try {
      return new Date(iso).toLocaleString(undefined, {
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch {
      return iso;
    }
  };

  const connectionBadgeVariant =
    connectionStatus === 'connected' ? 'success' :
    connectionStatus === 'connecting' ? 'warning' : 'error';

  const connectionLabel =
    connectionStatus === 'connected' ? 'Live' :
    connectionStatus === 'connecting' ? 'Connecting\u2026' : 'Disconnected';

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding={24}>
        <Stack direction="vertical" gap={24}>

          {/* HEADER */}
          <Box
            padding="var(--ggui-spacing-6, 24px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Row align="center" justify="between" wrap={true} gap={12}>
              <Stack direction="vertical" gap={4}>
                <Text variant="h1" color="var(--ggui-color-primary-900, #0c4a6e)">
                  Market Watch
                </Text>
                <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">
                  {'Last Updated: ' + formatTimestamp(lastUpdated)}
                </Text>
              </Stack>
              <div role="status" aria-live="polite">
                <Badge variant={connectionBadgeVariant} size="sm" pill>
                  {connectionLabel}
                </Badge>
              </div>
            </Row>
          </Box>

          {/* CONNECTING STATE */}
          {connectionStatus === 'connecting' && stocks.length === 0 && (
            <Box padding="var(--ggui-spacing-12, 48px)">
              <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Connecting to market data\u2026
              </Text>
            </Box>
          )}

          {/* EMPTY STATE */}
          {connectionStatus !== 'connecting' && stocks.length === 0 && (
            <Box padding="var(--ggui-spacing-12, 48px)">
              <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stock data available.
              </Text>
            </Box>
          )}

          {/* STOCK CARDS GRID */}
          {stocks.length > 0 && (
            <div
              role="list"
              aria-live="polite"
              aria-label="Stock prices"
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
                gap: 'var(--ggui-spacing-4, 16px)',
              }}
            >
              {stocks.map((stock, index) => {
                const positive = isPositive(stock.change);
                const changeColor = getChangeColor(stock.change);
                const borderColor = getCardBorderColor(stock.change);
                const arrow = positive ? '\u25b2' : '\u25bc';

                return (
                  <div
                    key={stock.symbol ?? index}
                    role="listitem"
                    aria-label={(stock.symbol ?? 'Unknown') + ': ' + formatPrice(stock.price) + ', change ' + formatChange(stock.change)}
                    style={{
                      animation: motionEnabled ? animation.fadeIn : 'none',
                      animationDelay: motionEnabled ? (index * 60) + 'ms' : '0ms',
                      animationFillMode: 'both',
                    }}
                  >
                    <Card padding={20} shadow="sm" border={true}>
                      <div
                        style={{
                          borderLeft: '4px solid ' + borderColor,
                          paddingLeft: 'var(--ggui-spacing-4, 16px)',
                          transition: 'border-color 300ms cubic-bezier(0.4,0,0.2,1)',
                        }}
                      >
                        <Stack direction="vertical" gap={12}>

                          <Stack direction="vertical" gap={2}>
                            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                              {stock.symbol ?? '\u2014'}
                            </Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              {stock.name ?? 'Unknown Company'}
                            </Text>
                          </Stack>

                          <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                            {formatPrice(stock.price)}
                          </Text>

                          <Row align="center" gap={8}>
                            <Text variant="body" weight="semibold" color={changeColor}>
                              {formatChange(stock.change)}
                            </Text>
                            <Text variant="body" weight="semibold" color={changeColor}>
                              <span
                                aria-hidden="true"
                                style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', marginRight: 2 }}
                              >
                                {arrow}
                              </span>
                              {formatChangePercent(stock.changePercent)}
                            </Text>
                          </Row>

                        </Stack>
                      </div>
                    </Card>
                  </div>
                );
              })}
            </div>
          )}

        </Stack>
      </Container>
    </>
  );
}

import { useState, useCallback } from 'react';
import {
  Container, Card, Box, Stack, Row, Text, Input, Select,
  Checkbox, RadioGroup, Button, Divider, Spacer, Badge, Icon,
  MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface InitialProfile {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
  emailNotifications?: boolean;
  theme?: string;
}

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: InitialProfile;
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called with all profile data when user completes onboarding */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

const STEPS = ['Profile Setup', 'Preferences', 'Review & Confirm'] as const;
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const STEP_LABELS: Record<number, string> = {
  0: 'Step 1: Profile Setup',
  1: 'Step 2: Preferences',
  2: 'Step 3: Review & Confirm',
};

const STEP_PROGRESS_LABELS: Record<number, string> = {
  0: 'Step 1 of 3',
  1: 'Step 2 of 3',
  2: 'Step 3 of 3',
};

const STEP_NUMBERS = [1, 2, 3] as const;

export default function GeneratedComponent(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState(0);
  const [animationKey, setAnimationKey] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState<FormData>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? (avatarOptions.length > 0 ? avatarOptions[0] : ''),
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light',
  });

  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [errors, setErrors] = useState<Record<string, string>>({});

  const validateName = useCallback((value: string): string => {
    if (!value.trim()) return 'Name is required';
    return '';
  }, []);

  const validateEmail = useCallback((value: string): string => {
    if (!value.trim()) return 'Email is required';
    if (!EMAIL_REGEX.test(value)) return 'Please enter a valid email address';
    return '';
  }, []);

  const isStep1Valid =
    !validateName(formData.name) &&
    !validateEmail(formData.email) &&
    formData.avatar !== '';
  const isStep2Valid = formData.role !== '';
  const isCurrentStepValid =
    step === 0 ? isStep1Valid : step === 1 ? isStep2Valid : true;

  const updateField = <K extends keyof FormData>(field: K, value: FormData[K]) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleNameChange = (value: string) => {
    updateField('name', value);
    setTouched(prev => ({ ...prev, name: true }));
    setErrors(prev => ({ ...prev, name: validateName(value) }));
  };

  const handleEmailChange = (value: string) => {
    updateField('email', value);
    setTouched(prev => ({ ...prev, email: true }));
    setErrors(prev => ({ ...prev, email: validateEmail(value) }));
  };

  const handleAvatarSelect = (avatar: string) => updateField('avatar', avatar);
  const handleRoleChange = (value: string) => {
    updateField('role', value);
    setTouched(prev => ({ ...prev, role: true }));
    setErrors(prev => ({ ...prev, role: value ? '' : 'Please select a role' }));
  };
  const handleNotificationsChange = (checked: boolean) => updateField('emailNotifications', checked);
  const handleThemeChange = (value: string) => updateField('theme', value);

  const triggerAnimation = () => setAnimationKey(prev => prev + 1);

  const goNext = () => {
    if (step === 0) {
      const nameErr = validateName(formData.name);
      const emailErr = validateEmail(formData.email);
      setTouched({ name: true, email: true });
      setErrors(prev => ({ ...prev, name: nameErr, email: emailErr }));
      if (nameErr || emailErr || !formData.avatar) return;
    }
    if (step === 1) {
      setTouched(prev => ({ ...prev, role: true }));
      if (!formData.role) {
        setErrors(prev => ({ ...prev, role: 'Please select a role' }));
        return;
      }
    }
    if (step < STEPS.length - 1) { setStep(s => s + 1); triggerAnimation(); }
  };

  const goBack = () => {
    if (step > 0) { setStep(s => s - 1); triggerAnimation(); }
  };

  const handleComplete = async () => {
    setIsSubmitting(true);
    try {
      await onComplete?.({
        name: formData.name,
        email: formData.email,
        avatar: formData.avatar,
        role: formData.role,
        emailNotifications: formData.emailNotifications,
        theme: formData.theme,
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const getStepCircleAriaLabel = (i: number, isCompleted: boolean, isCurrent: boolean): string => {
    const base = STEP_LABELS[i] ?? '';
    if (isCompleted) return base + ' (completed)';
    if (isCurrent) return base + ' (current)';
    return base;
  };

  const renderStepIndicator = () => {
    const progressPercent = (step / (STEPS.length - 1)) * 100;
    return (
      <Stack direction="vertical" gap={16} align="stretch">
        <Row gap={0} justify="between" align="start">
          {STEPS.map((label, i) => {
            const isCompleted = i < step;
            const isCurrent = i === step;
            const isUpcoming = i > step;
            const stepNum = STEP_NUMBERS[i];
            return (
              <Stack key={label} direction="vertical" align="center" gap={8}>
                <div
                  role="listitem"
                  aria-current={isCurrent ? 'step' : undefined}
                  aria-label={getStepCircleAriaLabel(i, isCompleted, isCurrent)}
                  style={{
                    width: 40, height: 40,
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 'var(--ggui-font-size-sm, 14px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    transition: transition.colors,
                    background: isCompleted
                      ? 'var(--ggui-color-success-500, #22c55e)'
                      : isCurrent
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    color: isCompleted || isCurrent
                      ? 'var(--ggui-color-surface, #fafafa)'
                      : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    border: isUpcoming
                      ? '2px solid var(--ggui-color-outline, #d4d4d8)'
                      : '2px solid transparent',
                  }}
                >
                  {isCompleted ? '✓' : stepNum}
                </div>
                <Text variant="caption" align="center"
                  weight={isCurrent ? 'semibold' : 'normal'}
                  color={isCurrent ? 'var(--ggui-color-primary-700, #0369a1)' : isCompleted ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                >
                  {label}
                </Text>
              </Stack>
            );
          })}
        </Row>
        <div
          role="progressbar"
          aria-valuenow={step + 1}
          aria-valuemin={1}
          aria-valuemax={STEPS.length}
          aria-label={STEP_PROGRESS_LABELS[step] ?? 'Onboarding progress'}
          style={{ width: '100%', height: 4, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: 'var(--ggui-color-outlineVariant, #e4e4e7)', overflow: 'hidden' }}
        >
          <div style={{
            width: progressPercent + '%', height: '100%',
            borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
            background: 'linear-gradient(90deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-600, #0284c7))',
            transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)',
          }} />
        </div>
      </Stack>
    );
  };

  const nameError = touched.name ? errors.name : undefined;
  const emailError = touched.email ? errors.email : undefined;
  const roleError = touched.role ? errors.role : undefined;

  const renderStep1 = () => (
    <Stack direction="vertical" gap={20}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Profile Setup</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Tell us about yourself to get started.</Text>
      </Stack>
      <Input label="Full Name" placeholder="Enter your full name" value={formData.name} onChange={handleNameChange} required error={nameError} />
      <Input label="Email Address" type="email" placeholder="you@example.com" value={formData.email} onChange={handleEmailChange} required error={emailError} />
      <Stack direction="vertical" gap={8}>
        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Choose an Avatar</Text>
        <div role="radiogroup" aria-label="Avatar selection" style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          {avatarOptions.map((emoji) => {
            const isSelected = formData.avatar === emoji;
            return (
              <div
                key={emoji}
                role="radio"
                aria-checked={isSelected}
                aria-label={'Avatar ' + emoji}
                tabIndex={0}
                onClick={() => handleAvatarSelect(emoji)}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); handleAvatarSelect(emoji); } }}
                style={{
                  width: 56, height: 56,
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 28, cursor: 'pointer',
                  transition: transition.colors,
                  background: isSelected ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  border: isSelected ? '2px solid var(--ggui-color-primary-500, #0ea5e9)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                  boxShadow: isSelected ? '0 0 0 3px var(--ggui-color-primary-100, #e0f2fe)' : 'none',
                  outline: 'none',
                }}
              >
                {emoji}
              </div>
            );
          })}
        </div>
      </Stack>
    </Stack>
  );

  const renderStep2 = () => (
    <Stack direction="vertical" gap={20}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Preferences</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Customize your experience.</Text>
      </Stack>
      <Select label="Role" value={formData.role} onChange={handleRoleChange} options={roleOptions.map(r => ({ value: r, label: r }))} placeholder="Select your role" required error={roleError} />
      <Checkbox label="Email Notifications" checked={formData.emailNotifications} onChange={handleNotificationsChange} description="Receive email updates and notifications about your account activity." />
      <RadioGroup
        label="Theme Preference"
        value={formData.theme}
        onChange={handleThemeChange}
        options={[
          { value: 'light', label: 'Light', description: 'Clean, bright interface' },
          { value: 'dark', label: 'Dark', description: 'Easy on the eyes' },
        ]}
        direction="horizontal"
      />
    </Stack>
  );

  const renderStep3 = () => (
    <Stack direction="vertical" gap={20}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Review &amp; Confirm</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please review your selections before completing setup.</Text>
      </Stack>
      <Box padding={16} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
        <Stack direction="vertical" gap={12}>
          <Text variant="label" color="var(--ggui-color-primary-800, #075985)" weight="semibold">Profile Information</Text>
          <Row gap={16} align="center">
            <div style={{
              width: 48, height: 48,
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              background: 'var(--ggui-color-primary-100, #e0f2fe)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 24, flexShrink: 0,
              border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
            }}>
              {formData.avatar}
            </div>
            <Stack direction="vertical" gap={2}>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{formData.name}</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
            </Stack>
          </Row>
        </Stack>
      </Box>
      <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
        <Stack direction="vertical" gap={12}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">Preferences</Text>
          <Row gap={8} align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">Role:</Text>
            <Badge variant="primary" size="sm">{formData.role}</Badge>
          </Row>
          <Row gap={8} align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">Email Notifications:</Text>
            <Badge variant={formData.emailNotifications ? 'success' : 'default'} size="sm">
              {formData.emailNotifications ? 'Enabled' : 'Disabled'}
            </Badge>
          </Row>
          <Row gap={8} align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">Theme:</Text>
            <Badge variant="secondary" size="sm">{formData.theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Badge>
          </Row>
        </Stack>
      </Box>
    </Stack>
  );

  const renderCurrentStep = () => {
    const content = step === 0 ? renderStep1() : step === 1 ? renderStep2() : renderStep3();
    return (
      <div key={animationKey} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
        {content}
      </div>
    );
  };

  const nextStepLabel = STEPS[step + 1] ?? '';

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md">
        <Card padding={32} shadow="md">
          <Stack direction="vertical" gap={24}>
            <Text variant="h2" align="center" color="var(--ggui-color-onSurface, #18181b)">
              Welcome! Let&apos;s get you set up
            </Text>

            <div role="list" aria-label="Onboarding steps">
              {renderStepIndicator()}
            </div>

            <Divider margin={4} />

            {renderCurrentStep()}

            <Divider margin={4} />

            <Row justify="between" align="center">
              {step > 0 ? (
                <Button
                  variant="outline"
                  onClick={goBack}
                  aria-label={step === 2 ? 'Go back to preferences' : 'Go back to profile setup'}
                  leftIcon={<Icon name="chevron-left" size={16} />}
                >
                  {step === 2 ? 'Go Back' : 'Back'}
                </Button>
              ) : (
                <Spacer size={1} />
              )}

              {step < STEPS.length - 1 ? (
                <Button
                  variant="primary"
                  onClick={goNext}
                  disabled={!isCurrentStepValid}
                  aria-label={'Proceed to ' + nextStepLabel}
                  rightIcon={<Icon name="chevron-right" size={16} />}
                >
                  Next
                </Button>
              ) : (
                <Button
                  variant="primary"
                  onClick={handleComplete}
                  loading={isSubmitting}
                  disabled={isSubmitting}
                  aria-label="Complete onboarding setup"
                  leftIcon={<Icon name="check" size={16} />}
                >
                  {isSubmitting ? 'Completing...' : 'Complete Setup'}
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Container>
    </>
  );
}

import React from 'react';
import { 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider, 
  Box,
  Container
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * 
 * A reusable weather display template that presents current conditions
 * and a 5-day forecast in a clean, high-hierarchy layout.
 */
export default function WeatherCard({
  city = "San Francisco",
  temperature = 72,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 12,
  unit = "°F",
  forecast = [
    { day: "Mon", icon: "☀️", high: 75, low: 62 },
    { day: "Tue", icon: "🌤️", high: 72, low: 60 },
    { day: "Wed", icon: "☁️", high: 68, low: 58 },
    { day: "Thu", icon: "🌧️", high: 65, low: 55 },
    { day: "Fri", icon: "🌤️", high: 70, low: 59 },
  ]
}: Props) {

  // Helper to map conditions to emojis if specific icons aren't provided
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('shower')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    return '🌤️';
  };

  return (
    <Container maxWidth="sm" padding={0}>
      <Card 
        shadow="md" 
        padding="var(--ggui-spacing-6, 24px)"
        style={{ 
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
        }}
      >
        <Stack gap={24}>
          {/* Header: City Name */}
          <Stack gap={4}>
            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Current Conditions
            </Text>
          </Stack>

          {/* Main Display: Large Temp & Condition Icon */}
          <Row justify="between" align="center">
            <Stack gap={0}>
              <div style={{ display: 'flex', alignItems: 'flex-start' }}>
                <span style={{ 
                  fontSize: 'var(--ggui-font-size-4xl, 36px)', 
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
