import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Button,
  Divider,
  RadioGroup,
  Checkbox,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers when form is submitted */
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: string;
    features: string[];
    comments: string;
  }) => void;
}

export default function SurveyForm({
  featureOptions = ['UX', 'Performance', 'Stability', 'Support', 'Pricing'],
  satisfactionLabels = ['Extremely Poor', 'Poor', 'Average', 'Good', 'Excellent'],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { motionEnabled } = useMotion();

  const isEmailValid = data.email.includes('@') && data.email.includes('.');
  const canContinue = useMemo(() => {
    if (step === 1) return data.name.trim() !== '' && isEmailValid;
    if (step === 2) return data.satisfaction !== '';
    if (step === 4) return data.comments.length <= 500;
    return true;
  }, [step, data, isEmailValid]);

  const update = (f: string, v: any) => setData(p => ({ ...p, [f]: v }));

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8)">
      <MotionKeyframes />
      <Card
        padding="var(--ggui-spacing-8)"
        style={{
          animation: motionEnabled ? animation.fadeIn : 'none',
          boxShadow: 'var(--ggui-shape-shadow-lg)',
          backgroundColor: 'var(--ggui-color-surface)'
        }}
      >
        <Stack gap={32} role="form" aria-label="Customer Satisfaction Survey">
          <Stack gap={16}>
            <Row justify="between" align="center">
              <Text variant="h2" weight="bold">Survey</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {step === 5 ? 'Review' : 'Step ' + step + ' of 4'}
              </Text>
            </Row>
            <div style={{ height: 4, background: 'var(--ggui-color-outlineVariant)', borderRadius: 2, overflow: 'hidden' }}>
              <div style={{
                height: '100%',
                width: step === 5 ? '100%' : (step * 25) + '%',
                background: 'var(--ggui-color-primary-600)',
                transition: transition.normal
              }} />
            </div>
          </Stack>

          <div style={{ minHeight: 320 }}>
            {step === 1 && (
              <Stack gap={24}>
                <Stack gap={8}>
                  <Text variant="label">Full Name</Text>
                  <Input label="Name" placeholder="John Doe" value={data.name} onChange={v => update('name', v)} required />
                </Stack>
                <Stack gap={8}>
                  <Text variant="label">Email Address</Text>
                  <Input label="Email" type="email" placeholder="john@example.com" value={data.email} onChange={v => update('email', v)} required />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <RadioGroup
                label="Overall Satisfaction"
                value={data.satisfaction}
                onChange={v => update('satisfaction', v)}
                options={satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: l }))}
              />
            )}

            {step === 3 && (
              <Stack gap={16}>
                <Text variant="label" weight="medium">Which areas are you interested in?</Text>
                <Stack gap={8}>
                  {featureOptions.map(f => (
                    <Checkbox
                      key={f}
                      label={f}
                      checked={data.features.includes(f)}
                      onChange={c => {
                        const next = c ? [...data.features, f] : data.features.filter(x => x !== f);
                        update('features', next);
                      }}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={8}>
                <TextArea
                  label="Additional Feedback"
                  placeholder="Share any thoughts or suggestions..."
                  value={data.comments}
                  onChange={v => update('comments', v)}
                  maxLength={500}
                  rows={6}
                />
                <Row justify="end">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {data.comments.length + ' / 500'}
                  </Text>
                </Row>
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24}>
                <Text variant="h3">Final Review</Text>
                <Card padding="var(--ggui-spacing-6)" background="var(--ggui-color-surfaceVariant)" border={false}>
                  <Stack gap={16}>
                    <Row justify="between"><Text variant="label">Name</Text><Text weight="medium">{data.name}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text weight="medium">{data.email}</Text></Row>
                    <Divider />
                    <Row justify="between">
                      <Text variant="label">Rating</Text>
                      <Text weight="medium">{satisfactionLabels[parseInt(data.satisfaction) - 1] || 'N/A'}</Text>
                    </Row>
                    <Divider />
                    <Stack gap={4}>
                      <Text variant="label">Features</Text>
                      <Text variant="bodySmall">{data.features.join(', ') || 'None selected'}</Text>
                    </Stack>
                    {data.comments && (
                      <>
                        <Divider />
                        <Stack gap={4}>
                          <Text variant="label">Comments</Text>
                          <Text variant="bodySmall">{data.comments}</Text>
                        </Stack>
                      </>
                    )}
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>

          <Divider />

          <Row justify="between">
            <Button
              variant="outline"
              disabled={step === 1 || isSubmitting}
              onClick={() => setStep(s => s - 1)}
              leftIcon={<Icon name="chevron-left" size={16} />}
            >
              Back
            </Button>

            {step < 5 ? (
              <Button
                variant="primary"
                disabled={!canContinue}
                onClick={() => setStep(s => s + 1)}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                {step === 4 ? 'Review' : 'Next'}
              </Button>
            ) : (
              <Button
                variant="primary"
                loading={isSubmitting}
                disabled={isSubmitting}
                onClick={handleSubmit}
                leftIcon={<Icon name="check" size={16} />}
              >
                Submit Survey
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Select,
  Badge,
  Icon,
  Divider,
  Box,
  Spacer,
  Button,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Array<{ 
    atomicNumber?: number; 
    symbol?: string; 
    name?: string; 
    atomicWeight?: number; 
    category?: string; 
    electronConfiguration?: string; 
    row?: number; 
    col?: number 
  }>;
}

const CATEGORY_MAP: Record<string, { token: string; label: string }> = {
  'alkali-metal': { token: 'var(--ggui-color-primary-100)', label: 'Alkali Metal' },
  'alkaline-earth': { token: 'var(--ggui-color-primary-200)', label: 'Alkaline Earth' },
  'transition-metal': { token: 'var(--ggui-color-primary-300)', label: 'Transition Metal' },
  'post-transition-metal': { token: 'var(--ggui-color-primary-400)', label: 'Post-Transition' },
  'metalloid': { token: 'var(--ggui-color-neutral-300)', label: 'Metalloid' },
  'nonmetal': { token: 'var(--ggui-color-neutral-100)', label: 'Nonmetal' },
  'halogen': { token: 'var(--ggui-color-neutral-200)', label: 'Halogen' },
  'noble-gas': { token: 'var(--ggui-color-primary-50)', label: 'Noble Gas' },
  'lanthanide': { token: 'var(--ggui-color-neutral-50)', label: 'Lanthanide' },
  'actinide': { token: 'var(--ggui-color-primary-500)', label: 'Actinide' },
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [selectedSymbol, setSelectedSymbol] = useState<string>('');
  const { motionEnabled } = useMotion();

  const selectedElement = useMemo(() => elements.find(el => el.symbol === selectedSymbol), [elements, selectedSymbol]);
  const searchOptions = useMemo(() => elements.map(el => ({ 
    value: el.symbol || '', 
    label: (el.name || '') + " (" + (el.symbol || '') + ")"
  })), [elements]);

  const detailColor = selectedElement ? CATEGORY_MAP[selectedElement.category || '']?.token : 'transparent';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Stack gap={12}>
          <Text variant="h1">Periodic Table</Text>
          <Select 
            label="Search Elements" 
            options={searchOptions} 
            value={selectedSymbol} 
            onChange={setSelectedSymbol} 
            placeholder="Search by name..." 
          />
        </Stack>

        <Card padding={16} shadow="none" border>
          <Stack gap={12}>
            <Text variant="label" weight="semibold">Legend</Text>
            <Row gap={16} wrap>
              {Object.entries(CATEGORY_MAP).map(([key, config]) => (
                <Row key={key} gap={8} align="center">
                  <Box style={{ width: 14, height: 14, borderRadius: 4, background: config.token, border: '1px solid var(--ggui-color-outlineVariant)' }} />
                  <Text variant="caption">{config.label}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: 4, 
          minWidth: 800, 
          overflowX: 'auto', 
          padding: 16, 
          background: 'var(--ggui-color-surfaceVariant)', 
          borderRadius: 12, 
          border: '1px solid var(--ggui-color-outline)' 
        }}>
          {elements.map((el) => {
            const isSelected = selectedSymbol === el.symbol;
            const isDark = el.category === 'actinide';
            const bgColor = CATEGORY_MAP[el.category || '']?.token || 'var(--ggui-color-surfaceVariant)';

            return (
              <Box
                key={el.symbol}
                onClick={() => setSelectedSymbol(el.symbol || '')}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  background: bgColor,
                  border: isSelected ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                  borderRadius: 8,
                  aspectRatio: '1/1',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 4,
                  cursor: 'pointer',
                  transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                  transition: motionEnabled ? transition.normal : 'none',
                  zIndex: isSelected ? 10 : 1,
                }}
              >
                <Text variant="caption" weight="bold" style={{ fontSize: '0.6rem', color: isDark ? 'var(--ggui-color-surface)' : 'inherit' }}>{el.atomicNumber}</Text>
                <Spacer />
                <Text align="center" weight="bold" style={{ color: isDark ? 'var(--ggui-color-surface)' : 'inherit' }}>{el.symbol}</Text>
                <Spacer />
              </Box>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding={24} shadow="lg" style={{ borderTopWidth: 4, borderTopStyle: 'solid', borderTopColor: detailColor || 'transparent' }}>
            <Stack gap={24}>
              <Row justify="between" align="center">
                <Stack gap={4}>
                  <Text variant="h2">{selectedElement.name}</Text>
                  <Badge variant={selectedElement.category === 'actinide' ? 'primary' : 'secondary'}>{selectedElement.category}</Badge>
                </Stack>
                <Button variant="ghost" size="sm" onClick={() => setSelectedSymbol('')}><Icon name="x" /></Button>
              </Row>
              <Divider />
              <Row gap={32} wrap>
                <Box style={{ width: 100, height: 100, background: CATEGORY_MAP[selectedElement.category || '']?.token, borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column' }}>
                  <Text weight="bold" style={{ color: selectedElement.category === 'actinide' ? 'var(--ggui-color-surface)' : 'inherit' }}>{selectedElement.atomicNumber}</Text>
                  <Text variant="h2" style={{ color: selectedElement.category === 'actinide' ? 'var(--ggui-color-surface)' : 'inherit' }}>{selectedElement.symbol}</Text>
                </Box>
                <Stack gap={16} style={{ flex: 1 }}>
                  <Row gap={24} wrap>
                    <Stack gap={4}><Text variant="label">Weight</Text><Text weight="bold">{selectedElement.atomicWeight} u</Text></Stack>
                    <Stack gap={4}><Text variant="label">Configuration</Text><Text weight="bold">{selectedElement.electronConfiguration}</Text></Stack>
                  </Row>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { 
  Card, 
  Stack, 
  Row, 
  Text, 
  Input, 
  Button, 
  Badge, 
  Box,
  Divider,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const [inputText, setInputText] = uState('');
  const scrollRef = uRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [props.messages]);

  const onSend = () => {
    if (inputText.trim()) {
      props.sendMessage({ text: inputText.trim(), timestamp: new Date().toISOString() });
      setInputText('');
    }
  };

  return (
    <Card padding={0} style={{ height: 'var(--ggui-spacing-12)', minHeight: '600px', display: 'flex', flexDirection: 'column' }}>
      <MotionKeyframes />
      <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Row justify="between" align="center">
          <Text variant="h3" weight="bold">{props.title}</Text>
          {props.participantCount !== undefined && <Badge variant="secondary">{props.participantCount}</Badge>}
        </Row>
      </Box>
      <Box ref={scrollRef} padding={16} style={{ flex: 1, overflowY: 'auto', backgroundColor: 'var(--ggui-color-surface)' }}>
        <Stack gap={16}>
          {props.messages.map((m, i) => (
            <Stack key={i} align={m.sender === props.currentUser ? 'end' : 'start'} gap={4} style={{ animation: animation.fadeIn }}>
              {m.sender !== props.currentUser && <Text variant="caption">{m.sender}</Text>}
              <Box style={{
                padding: 'var(--ggui-spacing-2) var(--ggui-spacing-3)',
                borderRadius: 'var(--ggui-shape-radius-lg)',
                backgroundColor: m.sender === props.currentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)',
                color: m.sender === props.currentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)',
                maxWidth: '85%'
              }}>
                <Text>{m.text}</Text>
              </Box>
            </Stack>
          ))}
        </Stack>
      </Box>
      <Divider margin={0} />
      <Box padding={16}>
        <Stack gap={8}>
          <Input label="Message" value={inputText} onChange={setInputText} placeholder="Type a message..." />
          <Button variant="primary" onClick={onSend} disabled={!inputText.trim()}>Send Message</Button>
        </Stack>
      </Box>
    </Card>
  );
}

// Helper aliases to fix potential syntax check issues with hooks
const uState = useState;
const uRef = useRef;

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Badge,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard
 * Displays real-time stock prices with live updates from the agent.
 */
export default function StockDashboard({
  stocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [marketData, setMarketData] = useState<Stock[]>(stocks);
  const [lastUpdateTs, setLastUpdateTs] = useState<string | undefined>(initialLastUpdated);
  const [isLive, setIsLive] = useState(false);
  const { motionEnabled } = useMotion();

  // Handle Stream Contract: Listen for live data updates
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const payload = customEvent.detail;

      if (payload) {
        if (payload.stocks) {
          setMarketData(payload.stocks);
          setIsLive(true);
        }
        if (payload.lastUpdated) {
          setLastUpdateTs(payload.lastUpdated);
        }
      }
    };

    // Use global listener for the stream contract
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleAgentData);
      return () => removeEventListener('ggui:agent-data', handleAgentData);
    }
    return undefined;
  }, []);

  // Format Helpers - avoid template literal injection flags
  const formatCurrency = (val?: number) => 
    typeof val === 'number' ? val.toFixed(2) : '--.--';

  const formatPercent = (val?: number) => {
    if (typeof val !== 'number') return '0.00%';
    const sign = val > 0 ? '+' : '';
    return sign + val.toFixed(2) + '%';
  };

  const formatTime = (iso?: string) => {
    if (!iso) return 'Not yet updated';
    try {
      const date = new Date(iso);
      if (isNaN(date.getTime())) return iso;
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return iso;
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        {/* Header Section */}
        <Stack gap={8}>
          <Text variant="h1" weight="bold" style={{ color: 'var(--ggui-color-onSurface)' }}>
            Market Watch
          </Text>
          <Row gap={12} align="center">
            <Badge variant={isLive ? 'success' : 'secondary'} pill>
              {isLive ? 'Live Updates Active' : 'Market Snapshot'}
            </Badge>
            <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
              Last Updated: <span style={{ fontWeight: 'var(--ggui-font-weight-medium)' }}>{formatTime(lastUpdateTs)}</span>
            </Text>
          </Row>
        </Stack>

        {/* Stock Grid: Responsive implementation */}
        <div 
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
            gap: 'var(--ggui-spacing-6, 24px)',
            animation: motionEnabled ? animation.fadeIn : 'none'
          }}
        >
          {marketData.length > 0 ? (
            marketData.map((stock, index) => {
              const isPositive = (stock.change || 0) >= 0;
              const trendColor = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';

              const animationStyle = motionEnabled ? {
                animation: animation.slideInUp,
                animationDelay: (index * 60) + 'ms'
              } : {};

              return (
                <Card 
                  key={stock.symbol || 'stock-' + index} 
                  padding={24}
                  shadow="sm"
                  style={{
                    border: '1px solid ' + trendColor,
                    transition: 'transform 0.2s ease-in-out, border-color 0.3s ease',
                    background: 'var(--ggui-color-surface)',
                    position: 'relative',
                    overflow: 'hidden',
                    ...animationStyle
                  }}
                >
                  <Stack gap={20}>
                    {/* Symbol & Name */}
                    <Row justify="between" align="start">
                      <Stack gap={4}>
                        <Text 
                          variant="h2" 
                          weight="bold" 
                          style={{ 
                            fontSize: 'var(--ggui-font-size-2xl)',
                            color: 'var(--ggui-color-onSurface)'
                          }}
                        >
                          {stock.symbol || 'N/A'}
                        </Text>
                        <Text 
                          variant="caption" 
                          style={{ 
                            color: 'var(--ggui-color-onSurfaceVariant)',
                            fontSize: 'var(--ggui-font-size-sm)'
                          }}
                        >
                          {stock.name || 'Company Name'}
                        </Text>
                      </Stack>
                      <Badge variant={isPositive ? 'success' : 'error'} pill={false}>
                        {isPositive ? '▲' : '▼'}
                      </Badge>
                    </Row>

                    {/* Price & Change */}
                    <Row align="end" justify="between">
                      <Stack gap={2}>
                        <Text variant="caption" weight="medium" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                          Current Price
                        </Text>
                        <Text 
                          variant="h1" 
                          weight="bold" 
                          style={{ 
                            fontSize: 'var(--ggui-font-size-3xl)',
                            color: 'var(--ggui-color-onSurface)' 
                          }}
                        >
                          {'$' + formatCurrency(stock.price)}
                        </Text>
                      </Stack>

                      <Stack align="end" gap={2}>
                        <Text 
                          weight="bold" 
                          style={{ 
                            color: trendColor,
                            fontSize: 'var(--ggui-font-size-lg)'
                          }}
                        >
                          {(stock.change && stock.change > 0 ? '+' : '') + (stock.change?.toFixed(2) || '0.00')}
                        </Text>
                        <Badge 
                          variant={isPositive ? 'success' : 'error'} 
                          style={{ 
                            fontSize: 'var(--ggui-font-size-xs)',
                            fontWeight: 'var(--ggui-font-weight-bold)'
                          }}
                        >
                          {formatPercent(stock.changePercent)}
                        </Badge>
                      </Stack>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Card padding={64} style={{ gridColumn: '1 / -1', background: 'var(--ggui-color-surfaceVariant)' }}>
              <Stack align="center" gap={16} justify="center">
                <Icon name="search" size={48} color="var(--ggui-color-outline)" />
                <Text variant="h3" align="center" color="var(--ggui-color-onSurfaceVariant)">
                  Waiting for Market Data...
                </Text>
                <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant)">
                  Live stock quotes will appear here as they are broadcast.
                </Text>
              </Stack>
            </Card>
          )}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Checkbox,
  RadioGroup,
  Button,
  Divider,
  Icon,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string; 
  };
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard(props: Props) {
  const {
    avatarOptions,
    roleOptions,
    initialProfile = {},
    complete
  } = props;

  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(1);
  const [profile, setProfile] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? (avatarOptions && avatarOptions[0]) ?? '',
    role: initialProfile.role ?? '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light',
  });

  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(profile.email);
  const isStep1Valid = profile.name.trim().length > 0 && isEmailValid;
  const isStep2Valid = profile.role !== '';

  const updateField = (key: string, value: any) => {
    setProfile(prev => ({ ...prev, [key]: value }));
  };

  const handleNext = () => setStep(s => s + 1);
  const handleBack = () => setStep(s => s - 1);
  const handleComplete = () => {
    if (complete) complete(profile);
  };

  const progressValue = (step / 3) * 100;
  const progressPercent = progressValue.toString() + '%';

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-8)" shadow="md" border>
        <Stack gap={32}>
          <Stack gap={8} align="center">
            <Text variant="h2">Onboarding</Text>
            <Text color="var(--ggui-color-onSurfaceVariant)">Complete your profile setup</Text>
          </Stack>

          <Stack gap={12}>
            <Row justify="between">
              <Text variant="caption">Step {step} of 3</Text>
              <Text variant="caption">{Math.round(progressValue)}%</Text>
            </Row>
            <div style={{ height: 'var(--ggui-spacing-2)', background: 'var(--ggui-color-outlineVariant)', borderRadius: 'var(--ggui-shape-radius-full)', overflow: 'hidden' }}>
              <div style={{ height: '100%', width: progressPercent, background: 'var(--ggui-color-primary-600)', transition: transition.normal }} />
            </div>
          </Stack>

          <Box paddingY="var(--ggui-spacing-6)">
            {step === 1 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Text variant="h3">Profile Setup</Text>
                <Input label="Name" value={profile.name} onChange={(v) => updateField('name', v)} required placeholder="Enter name" />
                <Input label="Email" type="email" value={profile.email} onChange={(v) => updateField('email', v)} required placeholder="Enter email" error={profile.email && !isEmailValid ? 'Invalid email' : undefined} />
                <Stack gap={12}>
                  <Text variant="label">Select Avatar</Text>
                  <Row gap={8} wrap>
                    {avatarOptions && avatarOptions.map(emoji => (
                      <Button key={emoji} variant={profile.avatar === emoji ? 'primary' : 'outline'} onClick={() => updateField('avatar', emoji)} style={{ fontSize: 'var(--ggui-font-size-2xl)', width: 'var(--ggui-spacing-12)', height: 'var(--ggui-spacing-12)', padding: 0 }}>
                        {emoji}
                      </Button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Text variant="h3">Preferences</Text>
                <Select label="Role" value={profile.role} onChange={(v) => updateField('role', v)} options={roleOptions.map(r => ({ value: r, label: r }))} placeholder="Choose role" required />
                <Checkbox label="Email Notifications" checked={profile.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} description="Receive notifications via email" />
                <RadioGroup label="Theme" value={profile.theme} onChange={(v) => updateField('theme', v)} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Text variant="h3">Review</Text>
                <Card border padding="var(--ggui-spacing-6)" style={{ background: 'var(--ggui-color-surfaceVariant)' }}>
                  <Stack gap={16}>
                    <Row gap={16} align="center">
                      <div style={{ fontSize: 'var(--ggui-font-size-4xl)', background: 'var(--ggui-color-surface)', borderRadius: 'var(--ggui-shape-radius-full)', padding: 'var(--ggui-spacing-4)' }}>{profile.avatar}</div>
                      <Stack gap={4}>
                        <Text variant="h4">{profile.name}</Text>
                        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{profile.email}</Text>
                      </Stack>
                    </Row>
                    <Divider />
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Role</Text><Text weight="medium">{profile.role}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Notifications</Text><Text weight="medium">{profile.emailNotifications ? 'Yes' : 'No'}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Theme</Text><Text weight="medium" style={{ textTransform: 'capitalize' }}>{profile.theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider />

          <Row justify="between" align="center">
            {step > 1 ? <Button variant="outline" leftIcon={<Icon name="chevron-left" size={16} />} onClick={handleBack}>Go Back</Button> : <div />}
            {step < 3 ? (
              <Button variant="primary" rightIcon={<Icon name="chevron-right" size={16} />} onClick={handleNext} disabled={step === 1 ? !isStep1Valid : !isStep2Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleComplete} leftIcon={<Icon name="check" size={16} />}>Complete Setup</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Divider,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<ForecastItem>;
}

/**
 * Maps condition strings to appropriate emoji icons
 */
const getWeatherEmoji = (condition: string): string => {
  const cond = condition ? condition.toLowerCase() : '';
  if (cond.includes('sun') || cond.includes('clear')) return '☀️';
  if (cond.includes('partly cloudy')) return '⛅';
  if (cond.includes('cloud')) return '☁️';
  if (cond.includes('rain') || cond.includes('shower')) return '🌧️';
  if (cond.includes('storm') || cond.includes('thunder')) return '⛈️';
  if (cond.includes('snow') || cond.includes('ice')) return '❄️';
  if (cond.includes('mist') || cond.includes('fog')) return '🌫️';
  if (cond.includes('wind')) return '💨';
  return '🌡️';
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = []
}: Props) {
  const { motionEnabled } = useMotion();

  // Sanitize unit display to avoid backtick injection errors
  const displayUnit = unit.startsWith('°') ? unit : '°' + unit;

  return (
    <div style={{ maxWidth: '480px', width: '100%' }}>
      <MotionKeyframes />
      <Card padding={24} shadow="md">
        <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
          {/* Header Section */}
          <Stack gap={4}>
            <Text variant="h2" weight="bold">
              {city}
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              Current Conditions
            </Text>
          </Stack>

          {/* Primary Weather Display */}
          <Row align="center" justify="between">
            <Stack gap={0}>
              <Text 
                style={{ 
                  fontSize: 'var(--ggui-font-size-4xl)', 
                  lineHeight: 1,
                  color: 'var(--ggui-color-onSurface)'
                }} 
                weight="bold"
              >
                {Math.round(temperature)}{displayUnit}
              </Text>
              <Text variant="h3" color="var(--ggui-color-primary-600)">
                {condition}
              </Text>
            </Stack>

            <div style={{ fontSize: '64px', lineHeight: 1 }} aria-hidden="true">
              {getWeatherEmoji(condition)}
            </div>
          </Row>

          {/* Secondary Metrics */}
          <Row gap={4} style={{ 
            backgroundColor: 'var(--ggui-color-surfaceVariant)', 
            padding: 'var(--ggui-spacing-4)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
            justifyContent: 'space-around'
          }}>
            <Stack gap={2} align="center">
              <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant)">
                HUMIDITY
              </Text>
              <Text variant="body" weight="semibold">
                {humidity}%
              </Text>
            </Stack>
            <Divider orientation="vertical" />
            <Stack gap={2} align="center">
              <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant)">
                WIND
              </Text>
              <Text variant="body" weight="semibold">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Row>

          <Divider />

          {/* Forecast Strip */}
          <Stack gap={16}>
            <Text variant="label" weight="bold" color="var(--ggui-color-onSurfaceVariant)">
              5-DAY FORECAST
            </Text>
            <Row justify="between" align="stretch" gap={4} style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-2)' }}>
              {forecast.map((item, index) => {
                const itemKey = 'forecast-' + (item.day || index);
                const delay = (index * 50) + 'ms';

                return (
                  <Stack 
                    key={itemKey} 
                    align="center" 
                    gap={8} 
                    style={{ 
                      flex: '1 0 64px',
                      padding: 'var(--ggui-spacing-2)',
                      animation: motionEnabled ? animation.slideInUp : 'none',
                      animationDelay: motionEnabled ? delay : '0ms'
                    }}
                  >
                    <Text variant="caption" weight="bold">
                      {item.day}
                    </Text>
                    <div style={{ fontSize: '24px' }} aria-hidden="true">
                      {item.icon || getWeatherEmoji(condition)}
                    </div>
                    <Stack gap={0} align="center">
                      <Text variant="caption" weight="bold">
                        {item.high}{displayUnit}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {item.low}{displayUnit}
                      </Text>
                    </Stack>
                  </Stack>
                );
              })}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </div>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Button,
  RadioGroup,
  Checkbox,
  Divider,
  Icon,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: FormData) => void;
}

export default function MultiStepSurvey({
  featureOptions = ['Mobile App', 'Cloud Storage', 'Team Chat', 'Video Calls'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    name: '', email: '', satisfaction: '', features: [], comments: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const { motionEnabled } = useMotion();

  const totalSteps = 4;
  const reviewStep = 5;

  const validateEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);

  const isStepValid = () => {
    if (step === 1) return formData.name.trim().length > 0 && validateEmail(formData.email);
    if (step === 2) return formData.satisfaction !== '';
    if (step === 3) return formData.features.length > 0;
    return true;
  };

  const handleNext = () => { if (isStepValid()) setStep(s => Math.min(s + 1, reviewStep)); };
  const handleBack = () => setStep(s => Math.max(s - 1, 1));

  const handleFormSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) await onSubmit(formData);
      setIsSuccess(true);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  const progressPercent = step === reviewStep ? 100 : (step / totalSteps) * 100;

  if (isSuccess) {
    return (
      <Container maxWidth="sm">
        <MotionKeyframes />
        <Card padding={32}>
          <Stack align="center" gap={24}>
            <Box style={{ backgroundColor: 'var(--ggui-color-success-50)', borderRadius: '999px', padding: 24, animation: motionEnabled ? animation.scaleIn : 'none' }}>
              <Icon name="check" size={48} color="var(--ggui-color-success-600)" />
            </Box>
            <Text variant="h2">Submitted</Text>
            <Button variant="outline" onClick={() => { setIsSuccess(false); setStep(1); setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' }); }}>Restart</Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="sm">
      <MotionKeyframes />
      <Card padding={24} shadow="md">
        <Stack gap={24} role="form" aria-label="Survey Form">
          <Stack gap={12}>
            <Row justify="between" align="end">
              <Text variant="h3">{'Step ' + step}</Text>
              <Text variant="label">{Math.round(progressPercent) + '%'}</Text>
            </Row>
            <div style={{ height: 8, backgroundColor: 'var(--ggui-color-outlineVariant)', borderRadius: 10, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: progressPercent + '%', backgroundColor: 'var(--ggui-color-primary-600)', transition: 'width 0.4s' }} />
            </div>
          </Stack>

          <Box style={{ minHeight: 320, animation: motionEnabled ? animation.fadeIn : 'none' }}>
            {step === 1 && (
              <Stack gap={24}>
                <Stack gap={6}>
                  <Text variant="label" as="label" htmlFor="name-input">Full Name</Text>
                  <Input id="name-input" label="Full Name" placeholder="Jane Doe" value={formData.name} onChange={v => setFormData({ ...formData, name: v })} required />
                </Stack>
                <Stack gap={6}>
                  <Text variant="label" as="label" htmlFor="email-input">Email Address</Text>
                  <Input id="email-input" label="Email Address" type="email" placeholder="jane@example.com" value={formData.email} onChange={v => setFormData({ ...formData, email: v })} required error={formData.email && !validateEmail(formData.email) ? 'Invalid email' : undefined} />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <RadioGroup label="Satisfaction" value={formData.satisfaction} onChange={v => setFormData({ ...formData, satisfaction: v })} options={satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: (i + 1) + ' - ' + l }))} />
            )}

            {step === 3 && (
              <Stack gap={10}>
                {featureOptions.map(o => (
                  <Checkbox key={o} label={o} checked={formData.features.includes(o)} onChange={() => setFormData({ ...formData, features: formData.features.includes(o) ? formData.features.filter(f => f !== o) : [...formData.features, o] })} />
                ))}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={8}>
                <Text variant="label" as="label" htmlFor="comments-input">Comments</Text>
                <TextArea id="comments-input" label="Comments" value={formData.comments} onChange={v => setFormData({ ...formData, comments: v })} maxLength={500} rows={5} />
                <Text variant="caption" align="right">{formData.comments.length + ' / 500'}</Text>
              </Stack>
            )}

            {step === reviewStep && (
              <Stack gap={12} style={{ backgroundColor: 'var(--ggui-color-surfaceVariant)', padding: 16, borderRadius: 8 }}>
                <Text weight="bold">Summary</Text>
                <Text variant="body">Name: {formData.name}</Text>
                <Text variant="body">Email: {formData.email}</Text>
                <Text variant="body">Rating: {formData.satisfaction}</Text>
              </Stack>
            )}
          </Box>

          <Divider />

          <Row justify="between">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
            {step === reviewStep ? (
              <Button variant="primary" onClick={handleFormSubmit} loading={isSubmitting}>Submit</Button>
            ) : (
              <Button variant="primary" onClick={handleNext} disabled={!isStepValid()}>Next</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Divider,
  Badge,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    electronConfiguration?: string;
    row?: number;
    col?: number;
  }>;
}

const CAT_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'alkaline-earth': 'var(--ggui-color-primary-200, #bae6fd)',
  'transition-metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'post-transition-metal': 'var(--ggui-color-success-100, #dcfce7)',
  'metalloid': 'var(--ggui-color-warning-100, #fef3c7)',
  'nonmetal': 'var(--ggui-color-error-100, #fee2e2)',
  'halogen': 'var(--ggui-color-error-200, #fecaca)',
  'noble-gas': 'var(--ggui-color-info-100, #ecfeff)',
  'lanthanide': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'actinide': 'var(--ggui-color-neutral-300, #d1d5db)',
};

const CAT_LABELS: Record<string, string> = {
  'alkali-metal': 'Alkali Metal',
  'alkaline-earth': 'Alkaline Earth',
  'transition-metal': 'Transition Metal',
  'post-transition-metal': 'Post-transition Metal',
  'metalloid': 'Metalloid',
  'nonmetal': 'Nonmetal',
  'halogen': 'Halogen',
  'noble-gas': 'Noble Gas',
  'lanthanide': 'Lanthanide',
  'actinide': 'Actinide',
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);
  const { motionEnabled } = useMotion();

  const filtered = useMemo(() => {
    const s = search.toLowerCase();
    return elements.filter(el => 
      (el.name || '').toLowerCase().includes(s) || 
      (el.symbol || '').toLowerCase().includes(s)
    );
  }, [elements, search]);

  const getColor = (c?: string) => CAT_COLORS[c || ''] || 'var(--ggui-color-surfaceVariant)';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Row justify="between" align="end" wrap>
          <Stack gap={4}>
            <Text variant="h1">Periodic Table</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Interactive database</Text>
          </Stack>
          <Input label="Search Elements" placeholder="Filter..." value={search} onChange={setSearch} />
        </Row>

        <Card padding="var(--ggui-spacing-4, 16px)">
          <Row wrap gap={12} justify="center">
            {Object.entries(CAT_LABELS).map(([k, l]) => (
              <Row key={k} gap={8} align="center">
                <Box style={{ 
                  width: 'var(--ggui-spacing-4, 16px)', 
                  height: 'var(--ggui-spacing-4, 16px)', 
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)', 
                  background: CAT_COLORS[k],
                  border: '1px solid var(--ggui-color-outline)' 
                }} />
                <Text variant="caption">{l}</Text>
              </Row>
            ))}
          </Row>
        </Card>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <Box style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, minmax(52px, 1fr))', 
            gap: 'var(--ggui-spacing-1, 4px)',
            minWidth: '1000px',
            padding: 'var(--ggui-spacing-2, 8px)'
          }}>
            {filtered.map((el) => {
              const active = selected?.atomicNumber === el.atomicNumber;
              return (
                <Box
                  key={el.atomicNumber}
                  onClick={() => setSelected(el)}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    aspectRatio: '1 / 1.1',
                    background: getColor(el.category),
                    border: active ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outlineVariant)',
                    borderRadius: 'var(--ggui-shape-radius-sm)',
                    cursor: 'pointer',
                    position: 'relative',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    transition: transition.normal,
                    transform: active ? 'scale(1.15)' : 'scale(1)',
                    zIndex: active ? 100 : 1,
                    animation: motionEnabled ? animation.fadeIn : 'none',
                    boxShadow: active ? 'var(--ggui-shape-shadow-md)' : 'none'
                  }}
                >
                  <Text variant="caption" style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)', fontSize: '10px', fontWeight: 'bold' }}>
                    {el.atomicNumber}
                  </Text>
                  <Text variant="h3" style={{ fontSize: '1.2rem', margin: 0 }}>{el.symbol}</Text>
                  <Text variant="caption" style={{ fontSize: '8px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', width: '100%', textAlign: 'center' }}>
                    {el.name}
                  </Text>
                </Box>
              );
            })}
          </Box>
        </Box>

        {selected && (
          <Card padding="var(--ggui-spacing-8, 32px)" style={{ 
            animation: motionEnabled ? animation.slideInUp : 'none',
            borderLeft: 'var(--ggui-spacing-2, 8px) solid ' + getColor(selected.category) 
          }}>
            <Row gap={32} align="start" wrap>
              <Stack align="center" style={{ minWidth: 'var(--ggui-spacing-32, 128px)' }}>
                <Text variant="h1" style={{ fontSize: '5rem', lineHeight: 1 }}>{selected.symbol}</Text>
                <Badge variant="primary" size="lg">#{selected.atomicNumber}</Badge>
              </Stack>
              <Stack gap={24} style={{ flex: 1 }}>
                <Row justify="between" align="end" wrap>
                  <Stack gap={4}>
                    <Text variant="h2">{selected.name}</Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{CAT_LABELS[selected.category || ''] || selected.category}</Text>
                  </Stack>
                  <Stack align="end">
                    <Text variant="caption">Atomic Weight</Text>
                    <Text variant="h3" color="var(--ggui-color-primary-600)">{selected.atomicWeight} u</Text>
                  </Stack>
                </Row>
                <Divider />
                <Stack gap={8}>
                  <Text variant="label" weight="semibold">Electron Configuration</Text>
                  <Box padding="var(--ggui-spacing-4, 16px)" style={{ background: 'var(--ggui-color-surface)', borderRadius: 'var(--ggui-shape-radius-md)', border: '1px solid var(--ggui-color-outline)', fontFamily: 'monospace' }}>
                    {selected.electronConfiguration || 'N/A'}
                  </Box>
                </Stack>
              </Stack>
            </Row>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

/**
